#include <stdio.h>
#include <string.h>

char stack[100][100];
int top = -1;

void push(char *str) {
    strcpy(stack[++top], str);
}

char *pop() {
    return stack[top--];
}

char *prefixToInfix(char *prefix) {
    int n = strlen(prefix);
    for (int i = n - 1; i >= 0; i--) {
        char c = prefix[i];
        if (c == '+' || c == '-' || c == '*' || c == '/') {
            char *op1 = pop();
            char *op2 = pop();
            char *temp = (char *)malloc(100 * sizeof(char));
            sprintf(temp, "(%s%c%s)", op1, c, op2);
            push(temp);
        } else {
            char temp[2];
            temp[0] = c;
            temp[1] = '\0';
            push(temp);
        }
    }
    return pop();
}

int main() {
    char prefix[100];
    printf("Enter prefix expression: ");
    scanf("%s", prefix);
    printf("Infix Expression: %s\n", prefixToInfix(prefix));
    return 0;
}

